mapper.select:
SELECT sp.id AS supplier_product_id, sp.name AS product_name, sp.product_code AS product_code, sup.name AS supplier_name, COALESCE(st.quantity, 0) AS quantity, sp.retail_price AS retail_price FROM supplier_product sp LEFT JOIN inventory_stock st ON st.supplier_product_id = sp.id AND st.deleted = 0 LEFT JOIN supplier sup ON sup.id = sp.supplier_id AND sup.deleted = 0 WHERE sp.deleted = 0 AND sp.status = 1 AND sp.supplier_id = #{supplierId} AND sp.brand_id = #{brandId} AND sp.category_id = #{categoryId}
AND (sp.name LIKE CONCAT('%', #{kw}, '%') OR sp.product_code LIKE CONCAT('%', #{kw}, '%'))
ORDER BY (COALESCE(st.quantity, 0) > 0) DESC, sp.name ASC, sp.id ASC
